{
  "artefact_id": "billing-quality-stack",
  "owner": "ruslan@faion.net",
  "django_version": "5.2.1",
  "python_version": "3.12",
  "ruff": {
    "rule_groups": ["E", "W", "F", "I", "B", "C4", "UP", "SIM", "DJ", "T20"],
    "line_length": 100,
    "exclude_migrations": true,
    "per_file_ignores": {"apps/*/management/commands/*.py": ["T20"]}
  },
  "mypy": {
    "django_settings_module": "config.settings.test",
    "strict_files": ["apps/billing/services.py", "apps/billing/selectors.py", "apps/accounts/services.py"],
    "check_untyped_defs": true,
    "warn_unused_ignores": true
  },
  "pre_commit_hooks": [
    {"name": "ruff",         "stage": "commit", "fast": true},
    {"name": "ruff-format",  "stage": "commit", "fast": true},
    {"name": "mypy",         "stage": "commit", "fast": true},
    {"name": "manage.py check", "stage": "commit", "fast": true},
    {"name": "pytest",       "stage": "push",   "fast": false}
  ],
  "ci_gates": ["ruff check --no-fix", "ruff format --check", "mypy --strict apps/", "manage.py check --deploy --fail-level WARNING", "manage.py makemigrations --check --dry-run", "pip-audit --strict", "coverage-gate"],
  "coverage_threshold": 80,
  "version": "1.0.0",
  "last_reviewed": "2026-05-22"
}
